@SpringBootApplication
public class Application {
    public static void main(String[] args) { SpringApplication.run(Application.class, args); }

@Configuration
static class SecurityConfig {

    @Bean
    SecurityFilterChain filterChain(HttpSecurity http, ClientRegistrationRepository registrations) throws Exception {
        return http
                .authorizeHttpRequests(auth -> auth
                        .requestMatchers("/").permitAll()
                        .anyRequest().authenticated())
                .oauth2Login(login -> login
                        .authorizationEndpoint(endpoint -> endpoint
                                .authorizationRequestResolver(pkceResolver(registrations)))
                        .defaultSuccessUrl("/", true))
                .logout(l -> l.logoutSuccessHandler(logoutSuccessHandler(registrations)))
                .build();
    }

    // Spring Security defaults to no PKCE for confidential clients (ones with a client-secret).
    // SecureAuth requires PKCE even for confidential clients, matching defense-in-depth use cases
    // — so force code_challenge/S256 on every authorization request.
    private OAuth2AuthorizationRequestResolver pkceResolver(ClientRegistrationRepository registrations) {
        DefaultOAuth2AuthorizationRequestResolver resolver =
                new DefaultOAuth2AuthorizationRequestResolver(registrations, "/oauth2/authorization");
        resolver.setAuthorizationRequestCustomizer(OAuth2AuthorizationRequestCustomizers.withPkce());
        return resolver;
    }

    private LogoutSuccessHandler logoutSuccessHandler(ClientRegistrationRepository registrations) {
        OidcClientInitiatedLogoutSuccessHandler handler = new OidcClientInitiatedLogoutSuccessHandler(registrations);
        handler.setPostLogoutRedirectUri("{baseUrl}/");
        return handler;
    }

    @Bean
    OAuth2AuthorizedClientManager authorizedClientManager(
            ClientRegistrationRepository registrations,
            OAuth2AuthorizedClientRepository authorized) {
        DefaultOAuth2AuthorizedClientManager manager =
                new DefaultOAuth2AuthorizedClientManager(registrations, authorized);
        manager.setAuthorizedClientProvider(
                OAuth2AuthorizedClientProviderBuilder.builder()
                        .authorizationCode()
                        .refreshToken()
                        .build());
        return manager;
    }

    @Bean
    RefreshTokenOAuth2AuthorizedClientProvider refreshTokenProvider() {
        RefreshTokenOAuth2AuthorizedClientProvider provider = new RefreshTokenOAuth2AuthorizedClientProvider();
        // Default 60s clock skew skips refresh when the access token isn't near expiry.
        // For the manual "Refresh now" button we want every click to hit the token endpoint,
        // so force the provider to treat every token as expired.
        provider.setClockSkew(Duration.ofDays(36500));
        return provider;
    }
}

@Controller
static class HomeController {

    private static final DateTimeFormatter TIME_FMT =
            DateTimeFormatter.ofPattern("h:mm:ss a").withZone(ZoneId.systemDefault());

    private final OAuth2AuthorizedClientManager authorizedClientManager;

    HomeController(OAuth2AuthorizedClientManager authorizedClientManager) {
        this.authorizedClientManager = authorizedClientManager;
    }

    @GetMapping("/")
    @ResponseBody
    String home(
            @AuthenticationPrincipal OidcUser user,
            Authentication auth,
            HttpServletRequest req,
            HttpServletResponse res) {
        if (user == null) {
            return """
                <!doctype html>
                <html><head><title>SecureAuth Java Token Refresh Demo</title></head>
                <body>
                  <h1>SecureAuth Java Token Refresh Demo</h1>
                  <p><a href="/oauth2/authorization/secureauth">Sign in</a></p>
                </body></html>
                """;
        }
        String given = esc(user.getGivenName());
        String family = esc(user.getFamilyName());
        String email = esc(user.getEmail());
        String fullName = (given + " " + family).trim();
        String name = fullName.isBlank() ? "there" : fullName;
        String emailSuffix = email.isEmpty() ? "" : " (" + email + ")";

        // Route through the OAuth2AuthorizedClientManager so Spring's refresh-token provider
        // auto-refreshes once the access token is within clock-skew of expiry.
        OAuth2AuthorizeRequest authorizeRequest = OAuth2AuthorizeRequest
                .withClientRegistrationId("secureauth")
                .principal(auth)
                .attributes(attrs -> {
                    attrs.put(HttpServletRequest.class.getName(), req);
                    attrs.put(HttpServletResponse.class.getName(), res);
                })
                .build();
        OAuth2AuthorizedClient client = authorizedClientManager.authorize(authorizeRequest);
        String expiresAtDisplay = "unknown";
        if (client != null && client.getAccessToken().getExpiresAt() != null) {
            Instant expires = client.getAccessToken().getExpiresAt();
            expiresAtDisplay = TIME_FMT.format(expires);
        }

        // POST /refresh needs Spring Security's CSRF token; render it as a hidden field.
        CsrfToken csrf = (CsrfToken) req.getAttribute(CsrfToken.class.getName());

        return """
            <!doctype html>
            <html><head><title>SecureAuth Java Token Refresh Demo</title></head>
            <body>
              <h1>SecureAuth Java Token Refresh Demo</h1>
              <p>Welcome, %s%s</p>
              <p>Access token expires at: %s</p>
              <form method="POST" action="/refresh">
                <input type="hidden" name="%s" value="%s"/>
                <button type="submit">Refresh token now</button>
              </form>
              <p><a href="/logout">Sign out</a></p>
            </body></html>
            """.formatted(name, emailSuffix, esc(expiresAtDisplay),
                          esc(csrf.getParameterName()), esc(csrf.getToken()));
    }

    private static String esc(String s) {
        if (s == null) return "";
        return s.replace("&", "&amp;").replace("<", "&lt;").replace(">", "&gt;")
                .replace("\"", "&quot;").replace("'", "&#39;");
    }
}

    @Controller
    static class RefreshController {

        private final OAuth2AuthorizedClientRepository authorizedClientRepo;
        private final RefreshTokenOAuth2AuthorizedClientProvider refreshProvider;

        RefreshController(
                OAuth2AuthorizedClientRepository authorizedClientRepo,
                RefreshTokenOAuth2AuthorizedClientProvider refreshProvider) {
            this.authorizedClientRepo = authorizedClientRepo;
            this.refreshProvider = refreshProvider;
        }

        @PostMapping("/refresh")
        ResponseEntity<String> refresh(Authentication auth, HttpServletRequest req, HttpServletResponse res) {
            OAuth2AuthorizedClient current = authorizedClientRepo.loadAuthorizedClient("secureauth", auth, req);
            if (current == null) {
                return redirectToHome();
            }
            try {
                OAuth2AuthorizationContext ctx = OAuth2AuthorizationContext
                        .withAuthorizedClient(current)
                        .principal(auth)
                        .build();
                OAuth2AuthorizedClient refreshed = refreshProvider.authorize(ctx);
                if (refreshed != null) {
                    authorizedClientRepo.saveAuthorizedClient(refreshed, auth, req, res);
                }
                return redirectToHome();
            } catch (OAuth2AuthenticationException e) {
                String errorCode = e.getError() != null ? e.getError().getErrorCode() : null;
                return renderError(errorCode != null ? errorCode : (e.getMessage() != null ? e.getMessage() : "refresh failed"));
            } catch (Exception e) {
                return renderError(e.getMessage() == null ? "refresh failed" : e.getMessage());
            }
        }

        private static ResponseEntity<String> redirectToHome() {
            return ResponseEntity.status(HttpStatus.FOUND).header(HttpHeaders.LOCATION, "/").build();
        }

        private static ResponseEntity<String> renderError(String message) {
            String esc = message == null ? "" : message.replace("&", "&amp;").replace("<", "&lt;")
                    .replace(">", "&gt;").replace("\"", "&quot;").replace("'", "&#39;");
            String body = """
                <!doctype html>
                <html><head><title>SecureAuth Java Token Refresh Demo</title></head>
                <body>
                  <h1>SecureAuth Java Token Refresh Demo</h1>
                  <div style="color: red">
                    <p>Error: %s</p>
                    <p><a href="/">Back</a></p>
                  </div>
                </body></html>
                """.formatted(esc);
            return ResponseEntity.ok().contentType(MediaType.TEXT_HTML).body(body);
        }
    }
}

import * as client from "openid-client";
import { requireEnv } from "./env.js";

const config = await client.discovery(
  new URL("{{ISSUER_URL}}"),
  "{{CLIENT_ID}}",
  "{{CLIENT_SECRET}}",
);

export async function buildAuthUrl(
  codeVerifier: string,
  state: string,
): Promise<URL> {
  const codeChallenge = await client.calculatePKCECodeChallenge(codeVerifier);
  return client.buildAuthorizationUrl(config, {
    redirect_uri: "{{REDIRECT_URI}}",
    scope: "{{SCOPES}}",
    code_challenge: codeChallenge,
    code_challenge_method: "S256",
    state,
  });
}

export async function exchangeCode(params: {
  currentUrl: URL;
  codeVerifier: string;
  expectedState: string;
}): Promise<Tokens> {
  const response = await client.authorizationCodeGrant(
    config,
    params.currentUrl,
    {
      pkceCodeVerifier: params.codeVerifier,
      expectedState: params.expectedState,
    },
  );
  return toTokens(response);
}

export async function refreshTokens(refreshToken: string): Promise<Tokens> {
  const response = await client.refreshTokenGrant(config, refreshToken);
  return toTokens(response, refreshToken);
}

import crypto from "node:crypto";

function getSessionSecret(): string {
  const fromEnv = process.env.SESSION_SECRET;
  if (fromEnv) return fromEnv;
  console.warn(
    "[warn] SESSION_SECRET not set — generating a random value. Set SESSION_SECRET for production so sessions survive restarts.",
  );
  return crypto.randomBytes(32).toString("hex");
}

export function createApp(): Express {
  const app = express();

  app.use(
    session({
      secret: getSessionSecret(),
      resave: false,
      saveUninitialized: false,
      cookie: {
        secure: process.env.NODE_ENV === "production",
        httpOnly: true,
        sameSite: "lax",
      },
    }),
  );

  // Auto-refresh the access token when it's within 60s of expiring.
  // Runs on every request that has a session with a refresh token.
  app.use(async (req, _res, next) => {
    const now = Math.floor(Date.now() / 1000);
    if (
      req.session.refreshToken &&
      (req.session.accessTokenExpiresAt ?? 0) - now < 60
    ) {
      try {
        const tokens = await refreshTokens(req.session.refreshToken);
        req.session.user = tokens.claims;
        req.session.idToken = tokens.idToken;
        req.session.accessToken = tokens.accessToken;
        req.session.refreshToken = tokens.refreshToken;
        req.session.accessTokenExpiresAt = tokens.accessTokenExpiresAt;
      } catch {
        // Refresh failed — clear auth fields; next route will render sign-in.
        delete req.session.user;
        delete req.session.idToken;
        delete req.session.accessToken;
        delete req.session.refreshToken;
        delete req.session.accessTokenExpiresAt;
      }
    }
    next();
  });

  app.get("/", (req, res) => {
    if (req.session.user && req.session.accessTokenExpiresAt) {
      const expiresAt = new Date(
        req.session.accessTokenExpiresAt * 1000,
      ).toLocaleTimeString();
      res.send(renderSignedInPage(req.session.user, expiresAt));
    } else {
      res.send(renderSignedOutPage());
    }
  });

  app.get("/login", async (req, res, next) => {
    try {
      const codeVerifier = client.randomPKCECodeVerifier();
      const state = client.randomState();
      req.session.codeVerifier = codeVerifier;
      req.session.state = state;
      const url = await buildAuthUrl(codeVerifier, state);
      res.redirect(url.href);
    } catch (err) {
      next(err);
    }
  });

  app.get("/callback", async (req, res, next) => {
    const errorParam =
      typeof req.query.error === "string" ? req.query.error : undefined;
    if (errorParam) {
      const description =
        typeof req.query.error_description === "string"
          ? req.query.error_description
          : errorParam;
      const hint =
        typeof req.query.error_hint === "string"
          ? req.query.error_hint
          : undefined;
      res.send(renderErrorPage(description, hint));
      return;
    }

    const codeVerifier = req.session.codeVerifier;
    const expectedState = req.session.state;
    if (!codeVerifier || !expectedState) {
      res.send(renderErrorPage("Session expired. Please try again."));
      return;
    }

    try {
      const tokens = await exchangeCode({
        currentUrl: new URL(req.url, "{{REDIRECT_URI}}"),
        codeVerifier,
        expectedState,
      });
      await new Promise<void>((resolve, reject) => {
        req.session.regenerate((err) => (err ? reject(err) : resolve()));
      });
      req.session.user = tokens.claims;
      req.session.idToken = tokens.idToken;
      req.session.accessToken = tokens.accessToken;
      req.session.refreshToken = tokens.refreshToken;
      req.session.accessTokenExpiresAt = tokens.accessTokenExpiresAt;
      res.redirect("/");
    } catch (err) {
      if (res.headersSent) {
        next(err);
        return;
      }
      const message =
        err instanceof Error ? err.message : "Authentication failed";
      res.send(renderErrorPage(message));
    }
  });

  app.post(
    "/refresh",
    express.urlencoded({ extended: false }),
    async (req, res, next) => {
      const refreshToken = req.session.refreshToken;
      if (!refreshToken) {
        res.send(renderErrorPage("No session — sign in first."));
        return;
      }
      try {
        const tokens = await refreshTokens(refreshToken);
        req.session.user = tokens.claims;
        req.session.idToken = tokens.idToken;
        req.session.accessToken = tokens.accessToken;
        req.session.refreshToken = tokens.refreshToken;
        req.session.accessTokenExpiresAt = tokens.accessTokenExpiresAt;
        res.redirect("/");
      } catch (err) {
        if (res.headersSent) {
          next(err);
          return;
        }
        const message = err instanceof Error ? err.message : "Refresh failed";
        res.send(renderErrorPage(message));
      }
    },
  );

  app.get("/logout", (req, res) => {
    const idToken = req.session.idToken;
    req.session.destroy((err) => {
      if (err) {
        console.error("session destroy error:", err);
      }
      if (idToken) {
        res.redirect(buildLogoutUrl(idToken).href);
      } else {
        res.redirect("/");
      }
    });
  });

  return app;
}

// AllowUnsolicitedAuthnResponse enables IdP-initiated SSO alongside SP-initiated.
// The IdP signing certificate is loaded from disk via the path in SAML_IDP_SIGNING_CERT_PATH.
builder.Services.AddAuthentication(options =>
    {
        options.DefaultScheme = CookieAuthenticationDefaults.AuthenticationScheme;
        options.DefaultChallengeScheme = Saml2Defaults.Scheme;
    })
    .AddCookie()
    .AddSaml2(options =>
    {
        options.SPOptions.EntityId = new EntityId(RequireEnv("SAML_SP_ENTITY_ID"));
        options.SPOptions.ReturnUrl = new Uri("https://localhost:4262/");

        var idp = new IdentityProvider(new EntityId(RequireEnv("SAML_IDP_ENTITY_ID")), options.SPOptions)
        {
            SingleSignOnServiceUrl = new Uri(RequireEnv("SAML_IDP_SSO_URL")),
            Binding = Saml2BindingType.HttpRedirect,
            AllowUnsolicitedAuthnResponse = true,
        };
        // Signing key must be added BEFORE LoadMetadata = false — the setter triggers
        // IdentityProvider.Validate() which requires SigningKeys to be non-empty.
        idp.SigningKeys.AddConfiguredKey(LoadIdpCert(RequireEnv("SAML_IDP_SIGNING_CERT_PATH")));
        idp.LoadMetadata = false;
        options.IdentityProviders.Add(idp);
    });

builder.Services.AddAuthorization();

static string RequireEnv(string name) =>
    Environment.GetEnvironmentVariable(name)
        ?? throw new InvalidOperationException($"Missing required env var: {name}");

static X509Certificate2 LoadIdpCert(string path)
{
    var resolved = ResolveCertPath(path);
    if (resolved is null)
    {
        throw new FileNotFoundException(
            $"IdP signing cert not found searching for '{path}' from cwd up to filesystem root. " +
            $"Download it from the SecureAuth admin UI (SAML IdP → General → Download certificate) " +
            $"and save it at the sample root as {path}.");
    }
    return X509Certificate2.CreateFromPem(File.ReadAllText(resolved));
}

// Walk up from the current directory looking for the cert file (mirrors DotNetEnv's
// TraversePath behavior for .env). When `dotnet run --project src` runs the app, the
// working directory is `src/` but the cert lives at the sample root one level up.
static string? ResolveCertPath(string path)
{
    if (Path.IsPathRooted(path) && File.Exists(path)) return path;
    var fileName = Path.GetFileName(path);
    var dir = new DirectoryInfo(Environment.CurrentDirectory);
    while (dir is not null)
    {
        var candidate = Path.Combine(dir.FullName, fileName);
        if (File.Exists(candidate)) return candidate;
        dir = dir.Parent;
    }
    return null;
}

// Sustainsys.Saml2 mounts the SP endpoints (ACS, metadata, SLO) under /Saml2 automatically,
// so /login just issues a Saml2 challenge and the library handles the rest.
app.MapGet("/", (HttpContext ctx) =>
    ctx.User.Identity?.IsAuthenticated == true
        ? Results.Content(Views.RenderSignedInPage(ctx.User), "text/html")
        : Results.Content(Views.RenderSignedOutPage(), "text/html"));

app.MapGet("/login", () => Results.Challenge(
    new AuthenticationProperties { RedirectUri = "/" },
    [Saml2Defaults.Scheme]));

// CIAM does not implement SAML SLO. Logout clears the local cookie and redirects home.
app.MapGet("/logout", () => Results.SignOut(
    new AuthenticationProperties { RedirectUri = "/" },
    [CookieAuthenticationDefaults.AuthenticationScheme]));

@Configuration
static class SamlConfig {

    @Bean
    @ConditionalOnMissingBean
    RelyingPartyRegistrationRepository relyingPartyRegistrationRepository(
            @Value("${SAML_SP_ENTITY_ID}") String spEntityId,
            @Value("${SAML_IDP_ENTITY_ID}") String idpEntityId,
            @Value("${SAML_IDP_SSO_URL}") String idpSsoUrl,
            @Value("${SAML_IDP_SIGNING_CERT_PATH}") String idpCertPath) throws Exception {
        X509Certificate idpCert = loadCert(idpCertPath);
        // Spring Security 6.4 SAML2 always signs AuthnRequests; if no signing credential is
        // configured the request resolver throws "Failed to resolve any signing credential".
        // We reuse the dev TLS keystore (generated by keytool-maven-plugin) as the signing
        // credential. CIAM doesn't validate AuthnRequest signatures (no SP signing cert is
        // registered), so this is functionally equivalent to "unsigned" from the IdP's view.
        // For production, generate a dedicated SP signing key and register the public cert
        // in CIAM's SAML SP form so signatures are actually validated.
        Saml2X509Credential signingCredential = loadDevKeystoreSigningCredential();
        RelyingPartyRegistration registration = RelyingPartyRegistration
                .withRegistrationId("secureauth")
                .entityId(spEntityId)
                .assertionConsumerServiceLocation("{baseUrl}/login/saml2/sso/{registrationId}")
                .signingX509Credentials(c -> c.add(signingCredential))
                .assertingPartyMetadata(party -> party
                        .entityId(idpEntityId)
                        .singleSignOnServiceLocation(idpSsoUrl)
                        .singleSignOnServiceBinding(Saml2MessageBinding.POST)
                        .verificationX509Credentials(c -> c.add(Saml2X509Credential.verification(idpCert))))
                .build();
        return new InMemoryRelyingPartyRegistrationRepository(registration);
    }

    private static X509Certificate loadCert(String path) throws Exception {
        try (InputStream in = new FileInputStream(path)) {
            CertificateFactory cf = CertificateFactory.getInstance("X.509");
            return (X509Certificate) cf.generateCertificate(in);
        }
    }

    private static Saml2X509Credential loadDevKeystoreSigningCredential() throws Exception {
        KeyStore ks = KeyStore.getInstance("PKCS12");
        try (InputStream in = new ClassPathResource("dev-keystore.p12").getInputStream()) {
            ks.load(in, "changeit".toCharArray());
        }
        PrivateKey key = (PrivateKey) ks.getKey("localhost", "changeit".toCharArray());
        X509Certificate cert = (X509Certificate) ks.getCertificate("localhost");
        return Saml2X509Credential.signing(key, cert);
    }
}

@Configuration
static class SecurityConfig {

    @Bean
    SecurityFilterChain filterChain(HttpSecurity http) throws Exception {
        OpenSaml4AuthenticationProvider provider = new OpenSaml4AuthenticationProvider();
        Converter<OpenSaml4AuthenticationProvider.ResponseToken, Saml2ResponseValidatorResult> defaultValidator =
                OpenSaml4AuthenticationProvider.createDefaultResponseValidator();
        provider.setResponseValidator(token -> {
            Saml2ResponseValidatorResult result = defaultValidator.convert(token);
            List<Saml2Error> filtered = result.getErrors().stream()
                    .filter(e -> !Saml2ErrorCodes.INVALID_IN_RESPONSE_TO.equals(e.getErrorCode()))
                    .toList();
            return filtered.isEmpty()
                    ? Saml2ResponseValidatorResult.success()
                    : Saml2ResponseValidatorResult.failure(filtered);
        });
        // CIAM's SubjectConfirmation interacts badly with Spring Security's strict bearer
        // validator in two ways:
        //   1. The Address attribute is host:port form (e.g. "[::1]:57370") rather than
        //      IP-only. Disabled via SC_CHECK_ADDRESS=false.
        //   2. The session-stored AuthnRequest used to validate InResponseTo is unreliable
        //      across the cross-site POST from CIAM (cookie/session loss). Worked around by
        //      feeding the assertion's own InResponseTo back as the expected value, which
        //      makes the comparison pass vacuously.
        // Production-grade SPs should fix the upstream Address format and rely on session
        // state for InResponseTo. For a CIAM quickstart, this is acceptable: response-level
        // signature validation (against the IdP signing cert) still runs at the response
        // validator above, so we still confirm the assertion came from CIAM.
        provider.setAssertionValidator(assertionToken -> {
            String assertionInResponseTo = null;
            var subject = assertionToken.getAssertion().getSubject();
            if (subject != null) {
                for (var sc : subject.getSubjectConfirmations()) {
                    var data = sc.getSubjectConfirmationData();
                    if (data != null && data.getInResponseTo() != null) {
                        assertionInResponseTo = data.getInResponseTo();
                        break;
                    }
                }
            }
            final String expectedInResponseTo = assertionInResponseTo;
            return OpenSaml4AuthenticationProvider.createDefaultAssertionValidatorWithParameters(
                    params -> {
                        params.put(
                                org.opensaml.saml.saml2.assertion.SAML2AssertionValidationParameters.SC_CHECK_ADDRESS,
                                Boolean.FALSE);
                        if (expectedInResponseTo != null) {
                            params.put(
                                    org.opensaml.saml.saml2.assertion.SAML2AssertionValidationParameters.SC_VALID_IN_RESPONSE_TO,
                                    expectedInResponseTo);
                        }
                    })
                    .convert(assertionToken);
        });
        return http
                .authorizeHttpRequests(auth -> auth
                        .requestMatchers("/").permitAll()
                        .anyRequest().authenticated())
                .saml2Login(saml -> saml
                        .authenticationManager(new ProviderManager(provider))
                        .defaultSuccessUrl("/", true))
                // Accept GET on /logout (Spring Security 6.4's default confirmation page
                // requires POST + CSRF; for a quickstart we let a simple <a href="/logout">
                // link work directly).
                .logout(l -> l
                        .logoutRequestMatcher(new org.springframework.security.web.util.matcher.AntPathRequestMatcher("/logout"))
                        .logoutSuccessUrl("/"))
                // Disable CSRF for the demo. SAML2 ACS endpoint is already exempt by the
                // framework; this just removes the requirement on /logout. Production apps
                // with state-changing endpoints should re-enable CSRF.
                .csrf(c -> c.disable())
                .build();
    }
}

@Controller
static class HomeController {

    @GetMapping("/")
    @ResponseBody
    String home(@AuthenticationPrincipal Saml2AuthenticatedPrincipal user) {
        if (user == null) {
            return """
                    <!doctype html>
                    <html><head><title>SecureAuth Java SAML Demo</title></head>
                    <body>
                      <h1>SecureAuth Java SAML Demo</h1>
                      <p><a href="/saml2/authenticate/secureauth">Sign in</a></p>
                    </body></html>
                    """;
        }
        return """
                <!doctype html>
                <html><head><title>SecureAuth Java SAML Demo</title></head>
                <body>
                  <h1>SecureAuth Java SAML Demo</h1>
                  <p>Welcome, %s</p>
                  <p><a href="/logout">Sign out</a></p>
                </body></html>
                """.formatted(esc(user.getName()));
    }

    private static String esc(String s) {
        if (s == null) return "";
        return s
                .replace("&", "&amp;")
                .replace("<", "&lt;")
                .replace(">", "&gt;")
                .replace("\"", "&quot;")
                .replace("'", "&#39;");
    }
}

import fs from "node:fs";
import path from "node:path";
import { ValidateInResponseTo } from "@node-saml/node-saml";
import type { Profile } from "@node-saml/node-saml";
import { Strategy as SamlStrategy } from "@node-saml/passport-saml";
import type { VerifiedCallback } from "@node-saml/passport-saml";
import { requireEnv } from "./env.js";

export type SamlUser = {
  nameID: string;
  nameIDFormat?: string;
  attributes: Record<string, unknown>;
};

function readIdpCert(): string {
  const certPath = requireEnv("SAML_IDP_SIGNING_CERT_PATH");
  const resolved = path.isAbsolute(certPath)
    ? certPath
    : path.resolve(process.cwd(), certPath);
  if (!fs.existsSync(resolved)) {
    throw new Error(
      `IdP signing cert not found at ${resolved}. Download it from the SecureAuth admin UI (SAML IdP → General → Download certificate) and save it at ${certPath}.`,
    );
  }
  return fs.readFileSync(resolved, "utf-8");
}

export const samlStrategy = new SamlStrategy(
  {
    issuer: requireEnv("SAML_SP_ENTITY_ID"),
    callbackUrl: requireEnv("SAML_SP_ACS_URL"),
    entryPoint: requireEnv("SAML_IDP_SSO_URL"),
    idpIssuer: requireEnv("SAML_IDP_ENTITY_ID"),
    idpCert: readIdpCert(),
    // Allow both SP-initiated (with InResponseTo) and IdP-initiated (without).
    validateInResponseTo: ValidateInResponseTo.ifPresent,
    wantAssertionsSigned: true,
    signatureAlgorithm: "sha256",
    digestAlgorithm: "sha256",
    // SAML AuthnRequests are unsigned; CIAM accepts unsigned requests by default.
  },
  (profile: Profile | null, done: VerifiedCallback) => {
    if (!profile) {
      return done(new Error("SAML profile missing"));
    }
    const user: SamlUser = {
      nameID: profile.nameID,
      nameIDFormat: profile.nameIDFormat,
      attributes: (profile.attributes as Record<string, unknown>) ?? {},
    };
    done(null, user);
  },
  (_profile: Profile | null, done: VerifiedCallback) => {
    // Logout SAML — not implemented; CIAM does not support SLO. Local logout
    // is handled in app.ts by destroying the session. This callback exists
    // because passport-saml's Strategy constructor requires it.
    done(null);
  },
);

app.get(
  "/login",
  passport.authenticate("saml", {
    failureRedirect: "/",
    failureFlash: false,
  }),
);

app.post("/saml/acs", (req, res, next) => {
  passport.authenticate(
    "saml",
    (
      err: Error | null,
      user: SamlUser | false,
      info: { message?: string } | string | undefined,
    ) => {
      if (err) {
        return res.send(renderErrorPage(err.message));
      }
      if (!user) {
        const message =
          typeof info === "string"
            ? info
            : (info?.message ?? "SAML authentication failed");
        return res.send(renderErrorPage(message));
      }
      req.logIn(user, (loginErr) => {
        if (loginErr) return next(loginErr);
        res.redirect("/");
      });
    },
  )(req, res, next);
});

private func plist(_ key: String) -> String {
    Bundle.main.object(forInfoDictionaryKey: key) as? String ?? ""
}

struct AuthConfig {
    static let issuer = AuthConfig.buildIssuerURL(host: plist("CIAM_ISSUER_HOST"),
                                                  path: plist("CIAM_ISSUER_PATH"))
    static let clientId    = plist("CIAM_CLIENT_ID")
    static let redirectURI: URL? = {
        let scheme = plist("CIAM_REDIRECT_SCHEME")
        guard !scheme.isEmpty else { return nil }
        return URL(string: "\(scheme)://oauthredirect")
    }()
    static let scopes      = plist("CIAM_SCOPES").split(separator: " ").map(String.init)

    /// Combines an issuer host (which may include a port) with an optional workspace path.
    /// Returns nil if host is empty. Avoids a trailing slash so that
    /// `<issuer>/.well-known/openid-configuration` doesn't become `//.well-known/...`.
    static func buildIssuerURL(host: String, path: String) -> URL? {
        guard !host.isEmpty else { return nil }
        let trimmedPath = path.trimmingCharacters(in: CharacterSet(charactersIn: "/"))
        let urlString = trimmedPath.isEmpty ? "https://\(host)" : "https://\(host)/\(trimmedPath)"
        return URL(string: urlString)
    }
}

func signIn(presenting: UIViewController) async {
    error = nil
    expired = false
    do {
        guard let issuer = AuthConfig.issuer else {
            throw AuthError.misconfigured("CIAM_ISSUER_HOST is missing — fill in Config.xcconfig")
        }
        guard !AuthConfig.clientId.isEmpty else {
            throw AuthError.misconfigured("CIAM_CLIENT_ID is missing — fill in Config.xcconfig")
        }
        guard let redirectURI = AuthConfig.redirectURI else {
            throw AuthError.misconfigured("CIAM_REDIRECT_SCHEME is missing — fill in Config.xcconfig")
        }
        let config = try await discoverConfiguration(forIssuer: issuer)
        let request = OIDAuthorizationRequest(
            configuration: config,
            clientId: AuthConfig.clientId,
            scopes: AuthConfig.scopes,
            redirectURL: redirectURI,
            responseType: OIDResponseTypeCode,
            additionalParameters: nil
        )
        let authState = try await authStateByPresenting(request: request, presenting: presenting)
        state = authState
        scheduleExpiryTimer()
    } catch {
        self.error = error.localizedDescription
    }
}

func signOut() async {
    if let token = state?.lastTokenResponse?.accessToken {
        try? await revokeToken(token)  // best-effort — proceed with local logout regardless
    }
    state = nil
    expired = false
    expiryTask?.cancel()
}

import Config from "react-native-config";
import {
  authorize,
  revoke,
  type AuthConfiguration,
} from "react-native-app-auth";

const authConfig: AuthConfiguration = {
  issuer: "{{ISSUER_URL}}",
  clientId: "{{CLIENT_ID}}",
  redirectUrl: "{{REDIRECT_URI}}",
  scopes: "{{SCOPES}}".split(" "),
};

async function signIn() {
  setError(null);
  setExpired(false);
  try {
    const result = await authorize(authConfig);
    setAuthState(result);
  } catch (e) {
    setError(e instanceof Error ? e.message : String(e));
  }
}

async function signOut() {
  if (!authState) return;
  try {
    await revoke(authConfig, {
      tokenToRevoke: authState.accessToken,
      sendClientId: true,
    });
  } catch (e) {
    // Revocation is best-effort — proceed with local logout regardless.
    Alert.alert(
      "Sign-out warning",
      e instanceof Error ? e.message : String(e),
    );
  }
  setAuthState(null);
  setExpired(false);
}

import Config from "react-native-config";
import {
  authorize,
  refresh,
  revoke,
  type AuthConfiguration,
} from "react-native-app-auth";
import * as Keychain from "react-native-keychain";

const authConfig: AuthConfiguration = {
  issuer: "{{ISSUER_URL}}",
  clientId: "{{CLIENT_ID}}",
  redirectUrl: "{{REDIRECT_URI}}",
  scopes: "{{SCOPES}}".split(" "),
};

const signIn = useCallback(async () => {
  setError(null);
  try {
    const result: AuthorizeResult = await authorize(authConfig);
    const next: Tokens = {
      accessToken: result.accessToken,
      accessTokenExpirationDate: result.accessTokenExpirationDate,
      refreshToken: result.refreshToken ?? null,
      idToken: result.idToken ?? null,
    };
    setTokens(next);
    if (next.refreshToken) {
      await persistRefreshToken(next.refreshToken);
    }
  } catch (e) {
    setError(e instanceof Error ? e.message : String(e));
  }
}, []);

async function persistRefreshToken(refreshToken: string): Promise<void> {
  await Keychain.setGenericPassword("refreshToken", refreshToken, {
    service: KEYCHAIN_SERVICE,
    accessible: Keychain.ACCESSIBLE.WHEN_UNLOCKED,
  });
}

async function loadRefreshToken(): Promise<string | null> {
  const credentials = await Keychain.getGenericPassword({
    service: KEYCHAIN_SERVICE,
  });
  return credentials ? credentials.password : null;
}

async function clearRefreshToken(): Promise<void> {
  await Keychain.resetGenericPassword({ service: KEYCHAIN_SERVICE });
}

const refreshTokens = useCallback(async () => {
  setError(null);
  try {
    const stored = tokens?.refreshToken ?? (await loadRefreshToken());
    if (!stored) {
      setError("No refresh token available. Sign in first.");
      return;
    }
    const result: RefreshResult = await refresh(authConfig, {
      refreshToken: stored,
    });
    const next: Tokens = {
      accessToken: result.accessToken,
      accessTokenExpirationDate: result.accessTokenExpirationDate,
      refreshToken: result.refreshToken ?? stored,
      // Refresh responses don't always include a new id_token — keep the
      // previous one so the welcome message stays populated.
      idToken: result.idToken ?? tokens?.idToken ?? null,
    };
    setTokens(next);
    if (next.refreshToken && next.refreshToken !== stored) {
      await persistRefreshToken(next.refreshToken);
    }
  } catch (e) {
    // Refresh tokens can be revoked or expire — clear local state and surface the error.
    await clearRefreshToken();
    setTokens(null);
    setError(
      e instanceof Error
        ? `Refresh failed (${e.message}). Sign in again.`
        : `Refresh failed. Sign in again.`,
    );
  }
}, [tokens]);
